这是一个完整的 **debounce** 函数实现，支持 `leading`、`trailing`、`maxWait` 以及 Promise：

```javascript
/**
 * 创建一个防抖函数，在连续调用时只执行最后一次（或第一次）。
 *
 * @param {Function} fn      要防抖的原始函数
 * @param {number}   wait    等待时间（毫秒）
 * @param {Object}   options 可选配置
 * @param {boolean}  options.leading  是否在延迟开始前立即执行（默认 false）
 * @param {boolean}  options.trailing 是否在延迟结束后执行（默认 true）
 * @param {number}   options.maxWait  最大等待时间，保证在此期间内至少执行一次
 * @returns {Function} 防抖后的函数，附带 .cancel() 和 .flush() 方法
 */
function debounce(fn, wait, options = {}) {
  const { leading = false, trailing = true, maxWait } = options;

  let timer = null;           // setTimeout 句柄
  let lastCallTime = 0;      // 上一次调用的时间戳
  let lastInvokeTime = 0;    // 上一次实际执行的时间戳
  let lastArgs = null;       // 最近一次被传入的参数
  let lastThis = null;       // 最近一次调用时的 this
  let result = undefined;    // 最后一次执行的结果

  // 是否应该调用
  function shouldInvoke(time) {
    const timeSinceLastCall = time - lastCallTime;
    const timeSinceLastInvoke = time - lastInvokeTime;

    return (
      lastCallTime === 0 ||            // 从未调用过
      timeSinceLastCall >= wait ||     // 超过了等待时间
      (maxWait && timeSinceLastInvoke >= maxWait) // 超过最大等待时间
    );
  }

  // 实际执行
  function invokeFunc(time) {
    const args = lastArgs;
    const thisArg = lastThis;

    lastArgs = lastThis = null;
    lastInvokeTime = time;
    result = fn.apply(thisArg, args);
    return result;
  }

  // 启动定时器（trailing 调用）
  function startTimer(pendingWait, time) {
    timer = setTimeout(() => timerExpired(time), pendingWait);
  }

  // 清除定时器
  function cancelTimer() {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
    }
  }

  // 定时器到期 —— 执行 trailing 调用
  function timerExpired(time) {
    const timeSinceLastCall = Date.now() - lastCallTime;
    const timeSinceLastInvoke = Date.now() - lastInvokeTime;

    // 如果距离上次调用间隔还不足 wait，重新计时
    if (timeSinceLastCall < wait && timeSinceLastCall >= 0) {
      // 但受 maxWait 约束
      if (maxWait && timeSinceLastInvoke >= maxWait) {
        return trailingEdge(time);
      }
      startTimer(wait - timeSinceLastCall, time);
    } else {
      trailingEdge(time);
    }
  }

  // leading 调用
  function leadingEdge(time) {
    lastInvokeTime = time;
    if (leading) {
      invokeFunc(time);
    }
    // 启动 trailing 定时器
    startTimer(wait, time);
  }

  // trailing 调用
  function trailingEdge(time) {
    cancelTimer();
    if (trailing && lastArgs) {
      invokeFunc(time);
    }
    lastArgs = lastThis = null;
  }

  // 返回的防抖函数
  function debounced(...args) {
    const time = Date.now();
    const isInvoking = shouldInvoke(time);

    lastArgs = args;
    lastThis = this;
    lastCallTime = time;

    if (isInvoking) {
      if (timer === null) {
        // 首次调用或上一次已经执行完
        return leadingEdge(time);
      }

      // 已经有一个 pending 的 timer，但 shouldInvoke 为 true
      // —— 说明触发了 maxWait
      if (maxWait) {
        cancelTimer();
        lastInvokeTime = time;
        result = invokeFunc(time);
        startTimer(wait, time);
        return result;
      }
    }

    if (timer === null) {
      startTimer(wait, time);
    }

    return result;
  }

  // 取消所有 pending 调用
  debounced.cancel = () => {
    cancelTimer();
    lastArgs = lastThis = lastCallTime = lastInvokeTime = 0;
  };

  // 立即执行 pending 调用
  debounced.flush = () => {
    if (timer !== null) {
      trailingEdge(Date.now());
    }
    return result;
  };

  return debounced;
}
```

---

## 使用示例

```javascript
// 基本防抖 —— 输入停止 300ms 后才执行
const search = debounce((query) => {
  console.log('搜索:', query);
}, 300);

search('a');
search('ab');
search('abc');    // 只有这次 300ms 后执行


// leading 模式 —— 立即执行第一次，之后防抖
const click = debounce(() => {
  console.log('点击处理');
}, 500, { leading: true, trailing: false });
// 第一次点击立即触发，500ms 内的连续点击被忽略


// 带 maxWait —— 保证每 1 秒至少执行一次（连续滚动场景）
const scroll = debounce(() => {
  console.log('滚动更新');
}, 200, { maxWait: 1000 });


// 取消和立即刷新
const fn = debounce(() => console.log('执行'), 1000);
fn();
fn.cancel();   // 取消 pending 调用

fn();
fn.flush();    // 立即执行


// 获取返回值（需要 trailing 执行）
const fn2 = debounce((x) => x * 2, 100);
const ret = fn2(3);  // ret 是 undefined（还没执行）
await new Promise(r => setTimeout(r, 150));
// 此时结果已存在，但 debounce 本身不返回 Promise
```

---

## 核心概念速览

| 配置 | 效果 |
|------|------|
| `leading: true` | 第一次调用立即执行，后续防抖 |
| `trailing: true` (默认) | 停止触发后执行最后一次 |
| `leading + trailing` | 第一次立即执行 + 最后一次也执行 |
| `maxWait` | 保证在指定时间内至少执行一次，防止 starvation |

这个实现参考了 Lodash `_.debounce` 的行为模式，但更精简，没有依赖外部库。适合直接用于项目或作为面试手写代码的参考。

